#include "strategybase.h"  StrategyBase::StrategyBase(QObject *parent)     : QObject(parent)     , m_hasPosition(false)     , m_entryPrice(0.0)     , m_stopLossPrice(0.0)     , m_takeProfitPrice(0.0) {     setConfig(StrategyConfig{}); }  void StrategyBase::setParameters(const StrategyParameters &params) {     m_params = params;     m_symbol = params.symbol;     m_config.symbol = params.symbol;     m_config.doubleMAConfig.fastMA = params.fastMA;     m_config.doubleMAConfig.slowMA = params.slowMA;     m_config.doubleMAConfig.barPeriodMinutes = params.barPeriodMinutes;     m_config.riskConfig.stopLossPercent = params.stopLossPercent;     m_config.riskConfig.takeProfitPercent = params.takeProfitPercent;     m_config.positionConfig.lotSize = params.lotSize; }  void StrategyBase::setConfig(const StrategyConfig& config) {     m_config = config;     m_symbol = config.symbol;      m_params.symbol = config.symbol;     m_params.fastMA = config.doubleMAConfig.fastMA;     m_params.slowMA = config.doubleMAConfig.slowMA;     m_params.barPeriodMinutes = config.doubleMAConfig.barPeriodMinutes;     m_params.stopLossPercent = config.riskConfig.stopLossPercent;     m_params.takeProfitPercent = config.riskConfig.takeProfitPercent;     m_params.lotSize = config.positionConfig.lotSize; }  void StrategyBase::syncPositionState(bool hasPosition, double entryPrice) {     if (!hasPosition) {         m_hasPosition = false;         m_entryPrice = 0.0;         m_stopLossPrice = 0.0;         m_takeProfitPrice = 0.0;         return;     }      if (m_hasPosition && m_entryPrice > 0.0) {         return;     }      m_hasPosition = true;     m_entryPrice = entryPrice > 0.0 ? entryPrice : m_entryPrice;     if (m_entryPrice > 0.0) {         m_stopLossPrice = m_entryPrice * (1.0 - m_config.riskConfig.stopLossPercent / 100.0);         m_takeProfitPrice = m_entryPrice * (1.0 + m_config.riskConfig.takeProfitPercent / 100.0);     } } void StrategyBase::reset() {     m_hasPosition = false;     m_entryPrice = 0.0;     m_stopLossPrice = 0.0;     m_takeProfitPrice = 0.0; }  void StrategyBase::emitSignal(SignalType type, double price, double volume, const QString& comment) {     StrategySignal signal;     signal.type = type;     signal.symbol = m_symbol;     signal.price = price;     signal.volume = volume;     signal.timestamp = QDateTime::currentDateTime();     signal.comment = comment;      emit signalGenerated(signal); }